// This function simulates running the user's compiled program
// and capturing its output. In a real system, 'program_path'
// would point to the compiled executable of the user's code.
std::string execute_user_program(const std::string& program_path, const std::string& input_data) {
    // Escape double quotes and backslashes in input_data for shell command
    std::string escaped_input_data = input_data;
    size_t pos = 0;
    while ((pos = escaped_input_data.find('"', pos)) != std::string::npos) {
        escaped_input_data.replace(pos, 1, "\\\"");
        pos += 2;
    }
    pos = 0;
    while ((pos = escaped_input_data.find('\\', pos)) != std::string::npos) {
        escaped_input_data.replace(pos, 1, "\\\\");
        pos += 2;
    }

    // Command to execute the user's program with input
    // Using 'echo -e' to handle newline characters and piping to the program
    std::string command = "echo -e \"" + escaped_input_data + "\" | " + program_path + " 2>&1";

    FILE* pipe = popen(command.c_str(), "r");
    if (!pipe) {
        return "ERROR: Could not execute user program.";
    }

    char buffer[128];
    std::string result = "";
    while (fgets(buffer, sizeof(buffer), pipe) != nullptr) {
        result += buffer;
    }
    pclose(pipe);
    return result;
}

